const items = $input.all();
const usageItems = items.filter(i => i.json.account_id);
const contactItems = items.filter(i => i.json.properties?.email);

// Build usage lookup
const usageMap = {};
usageItems.forEach(i => { usageMap[i.json.account_id] = i.json; });

const signals = [];
const LIMITS = { starter: 5, growth: 20, professional: 50, enterprise: 200 };
const now = Date.now();

contactItems.forEach(contact => {
  const p = contact.json.properties;
  const email = p.email?.value;
  const plan = p.plan_type?.value || 'growth';
  const limit = LIMITS[plan] || 20;
  const last_signal = p.expansion_signal_sent_at?.value;
  const days_since = last_signal ? (now - new Date(last_signal).getTime()) / (1000*60*60*24) : 999;
  if (days_since < 14) return; // Dedup: skip if signalled recently

  const usage = usageMap[contact.json.id];
  if (!usage) return;

  const fired = [];
  if (usage.seats_used >= limit * 0.85) fired.push({ type: 'seat_limit', detail: `${usage.seats_used}/${limit} seats used (${Math.round(usage.seats_used/limit*100)}%)` });
  if (usage.new_users_this_week >= 3) fired.push({ type: 'user_growth', detail: `${usage.new_users_this_week} new users added this week` });
  if (usage.features_enabled_this_month >= 3) fired.push({ type: 'feature_adoption', detail: `${usage.features_enabled_this_month} new features enabled this month` });
  if (parseFloat(p.mrr?.value || 0) < 200 && usage.api_calls_month > 10000) fired.push({ type: 'high_usage_low_mrr', detail: `${usage.api_calls_month} API calls on a low-tier plan` });

  if (fired.length > 0) {
    signals.push({ json: {
      contact_id: contact.json.id, email, company: p.company?.value,
      plan, limit, cs_owner: p.cs_rep_owner?.value, mrr: p.mrr?.value,
      signals: fired, primary_signal: fired[0]
    }});
  }
});

return signals;

